class HugeIconComponent(Component):
    """Huge Icon Component."""

    library = "hugeicons-react@0.3.0"


class HugeIcon(HugeIconComponent):
    """A HugeIcon component."""

    tag = "None"

    # The size of the icon in pixels.
    size: Var[int] = Var.create(16)

    @classmethod
    def create(cls, *children, **props) -> Component:
        """Initialize the Icon component.

        Run some additional checks on Icon component.

        Args:
            *children: The positional arguments
            **props: The keyword arguments

        Raises:
            AttributeError: The errors tied to bad usage of the Icon component.
            ValueError: If the icon tag is invalid.

        Returns:
            The created component.

        """
        if children:
            if len(children) == 1 and isinstance(children[0], str):
                props["tag"] = children[0]
                children = []
            else:
                msg = f"Passing multiple children to Icon component is not allowed: remove positional arguments {children[1:]} to fix"
                raise AttributeError(msg)
        if "tag" not in props:
            msg = "Missing 'tag' keyword-argument for HugeIcon"
            raise AttributeError(msg)

        if not isinstance(props["tag"], str):
            msg = f"Invalid icon tag: {props['tag']}."
            raise TypeError(msg)

        props["tag"] = (
            formatting.to_title_case(formatting.to_snake_case(props["tag"])) + "Icon"
        )
        props["alias"] = f"Huge{props['tag']}"
        props.setdefault("stroke_width", 2)
        return super().create(*children, **props)


hi = HugeIcon.create
